function minEatingSpeed(piles: number[], h: number): number {
  let lo = 1, hi = 0;
  for (const p of piles) if (p > hi) hi = p;
  const can = (k: number) => {
    let hours = 0;
    for (const p of piles) hours += Math.ceil(p / k);
    return hours <= h;
  };
  while (lo < hi) {
    const m = (lo + hi) >> 1;
    if (can(m)) hi = m; else lo = m + 1;
  }
  return lo;
}
